pub const fn from_size_alignment(
    size: usize,
    alignment: Alignment,
) -> Result<Self, LayoutError> {
    if Layout::is_size_alignment_valid(size, alignment) {
        // SAFETY: Layout::size invariants checked above.
        Ok(Layout { size, align: alignment })
    } else {
        Err(LayoutError)
    }
}

